form:Form.form:Scripts:
				function Solicitar()
{     
	if (Ctrl("c_estado")!=null) Ctrl("c_estado").SetXValue("Solicitado");
	return true;
}

function Rechazar()
{     
	if (Ctrl("c_estado")!=null) Ctrl("c_estado").SetXValue("Rechazado");
	return true;
}      

function EnableButtons()
{   
	if (Ctrl('l_automatica').GetXValue() != "1")
	{		
		CtrlEnabled("e_dias", true);
	}
	else
	{	
		CtrlEnabled("e_dias", false);	
	}

	if (window.location.href.toUpperCase().indexOf("/MINIMAIN.HTM?")>=0)
		CtrlEnabled("CANCEL",false);

	if (Ctrl('l_automatica').GetXValue() == "1")
	{
		/*if(Ctrl("lblYAYA").GetXValue()!="")
		{
			alert("DISABLE -- 1 ");
			CtrlEnabled("ENVIAR",false);
			return;
		} */

		if (Ctrl("lblERROR") && Ctrl("lblERROR").GetXValue()!="")
		{			
			CtrlEnabled("ENVIAR",false);	                           
			return;
		}

		if (Ctrl('f_desde_solicitud').GetXValue() == "" || Ctrl('f_hasta_solicitud').GetXValue() == "")
		{			
			CtrlEnabled("ENVIAR",false);	                           
			return;
		}
	}	
	CtrlEnabled("ENVIAR",true);	


}

function OnLoad()
{
	Ctrl('l_automatica').SetXValue("1");
	CtrlEnabled("e_dias_bonif",false);
	EnableButtons();
}               

function IterNEXT()
{
	var MyDte=Ctrl("IterPOS").GetXValue();
	if (MyDte=="") MyDte=formatDate(NowDate(),"yyyymm");
	MyDte=(parseInt(MyDte,10)+1);
	if (MyDte % 100 > 12) MyDte=MyDte+100-12;
	Ctrl("IterPOS").SetXValue(MyDte.toString());
	Ctrl("main").DoEvent("Refresh");
}

function IterPREV()
{
	var MyDte=Ctrl("IterPOS").GetXValue();
	if (MyDte=="") MyDte=formatDate(NowDate(),"yyyymm");
	MyDte=(parseInt(MyDte,10)-1);
	if (MyDte % 100 < 1) MyDte=MyDte-100+12;
	Ctrl("IterPOS").SetXValue(MyDte.toString());
	Ctrl("main").DoEvent("Refresh");
}                 

function retObject()
{
	this.processResult =function(xml)
	{      
		xml=new NomadXML(xml);
		Ctrl("IterESTRUCT").SetXValue(xml.GetAttr("id"));
		Ctrl("main").DoEvent("Refresh");
	}
}

function Call_Estructura()
{
	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUCTURA.Guia.autoflow","HELP",'<helper-mess text="" id="'+Ctrl("IterESTRUCT").GetXValue()+'" code=""/>',new retObject(),"S");
}

function ValidarFecha(MeCTRL)
{
	if (Ctrl("f_desde_solicitud").GetXValue()>=Ctrl("f_hasta_solicitud").GetXValue())
	{                          
		MeCTRL.SetError("El 'regreso al puesto de trabajo' tiene que ser posterior a la de 'inicio de las vacaciones'.");
		return false;
	}                  
	return true;
}

function CALCULAR_DIAS()
{
	if (Ctrl('l_automatica').GetXValue() == "1")
	{
		if (Ctrl('f_desde_solicitud').GetXValue() != "" && Ctrl('f_hasta_solicitud').GetXValue() != "")
			Ctrl('main').DoEvent('RECALCULAR_DIAS');
		else
			Ctrl("e_dias").SetXValue("");
	}	
}   

function ChgAuto()
{           	
	Ctrl('f_desde_solicitud').SetXValue("");
	Ctrl('f_hasta_solicitud').SetXValue("");	
	Ctrl('e_dias').SetXValue("");
	Ctrl('e_dias_bonif').SetXValue("");		
	if(Ctrl("e_dias_bonif").GetEnabled())
		CtrlEnabled("e_dias_bonif",false);
	else
		CtrlEnabled("e_dias_bonif",true);	
	EnableButtons();
}
